script:
docname = frappe.form_dict.get("docname")
doc = frappe.get_doc("Custom Course Schedule", docname)

if not doc.weekly_slots:
    frappe.throw("No weekly slots defined")

term = frappe.get_doc("Academic Term", doc.academic_term)
start_date = term.term_start_date
end_date = term.term_end_date

day_map = {
    "Monday": 0, "Tuesday": 1, "Wednesday": 2,
    "Thursday": 3, "Friday": 4, "Saturday": 5, "Sunday": 6
}

count = 0
current = start_date
while current <= end_date:
    weekday = current.weekday()
    for slot in doc.weekly_slots:
        if day_map.get(slot.day_of_week) == weekday:
            exists = frappe.db.exists("Course Schedule", {
                "student_group": doc.student_group,
                "schedule_date": current,
                "from_time": slot.from_time,
                "course": slot.course
            })
            if not exists:
                cs = frappe.get_doc({
                    "doctype": "Course Schedule",
                    "student_group": doc.student_group,
                    "course": slot.course,
                    "schedule_date": current,
                    "from_time": slot.from_time,
                    "to_time": slot.to_time,
                    "room": slot.room,
                    "instructor": slot.instructor
                })
                cs.insert(ignore_permissions=True)
                count += 1
    current = frappe.utils.add_days(current, 1)

frappe.response["message"] = {"count": count}
